import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classic() {
        // sorted: 1,2,3,4,5,6 => 2nd smallest = 2
        assertEquals(2, new Solution().kthSmallest(new int[]{3, 2, 1, 5, 6, 4}, 2));
    }

    @Test
    void fourthSmallest() {
        // sorted: 3,4,7,10,15,20 => 4th smallest = 10
        assertEquals(10, new Solution().kthSmallest(new int[]{7, 10, 4, 3, 20, 15}, 4));
    }

    @Test
    void kEqualsOne() {
        // minimum element
        assertEquals(1, new Solution().kthSmallest(new int[]{5, 3, 1, 4, 2}, 1));
    }

    @Test
    void kEqualsLength() {
        // maximum element (kth = last in asc order)
        assertEquals(20, new Solution().kthSmallest(new int[]{7, 10, 4, 3, 20, 15}, 6));
    }

    @Test
    void singleElement() {
        assertEquals(42, new Solution().kthSmallest(new int[]{42}, 1));
    }

    @Test
    void allDuplicates() {
        // all same value
        assertEquals(5, new Solution().kthSmallest(new int[]{5, 5, 5, 5}, 3));
    }

    @Test
    void sortedInput() {
        // already sorted — must not degrade; k=3 => 3
        assertEquals(3, new Solution().kthSmallest(new int[]{1, 2, 3, 4, 5}, 3));
    }
}
